from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a phrase
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language phrase for a single predicate."""
        # Strip surrounding quotes and whitespace
        obj = obj.strip().strip('"')
        # Normalise predicate for lookup
        p = pred.lower().replace(" ", "")
        # Helper to format ISO dates nicely
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        # Mapping of predicates to phrase templates
        if p == "birthdate":
            return f"{subj} was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "deathdate":
            return f"{subj} died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "nationality":
            # Use natural phrasing for nationality.
            # Special case for United States to produce "American".
            low_obj = obj.lower()
            if "united states" in low_obj:
                return f"{subj} is an American"
            # Generic fallback: indicate origin.
            return f"{subj} is from {obj}"
        if p == "occupation":
            return f"{subj} was a {obj}"
        if p == "status":
            # Use lowercase for common status values to match expected phrasing
            low = obj.lower()
            if low == "retired":
                return f"{subj} is retired"
            # Fallback: keep original wording but lowercase first letter
            return f"{subj} is {low}"
        if p == "selectedbynasa":
            return f"{subj} was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut
            return f"{subj} was a crew member of {obj}"
        if p == "timeinspace":
            # Convert minutes to hours/minutes if possible
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"{subj} spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"{subj} spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"{subj} spent {obj} minutes in space"
        if p == "title":
            return f"{subj} held the title of {obj}"
        if p == "award":
            return f"{subj} received the {obj}"
        if p == "awards":
            return f"{subj} received {obj} awards"
        if p == "ribbonaward":
            return f"{subj} was awarded the {obj}"
        if p == "operator":
            # Subject is a mission/spacecraft
            # Prefer phrasing matching reference sentences
            return f"The {subj} was operated by {obj}"
        if p == "senators":
            return f"{obj} is a senator from {subj}"
        if p == "commander":
            # Subject is a mission; object is the astronaut who commanded it
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            # Subject is a mission; object is the astronaut who was backup pilot
            return f"{obj} was the backup pilot for {subj}"
        if p == "crewmembers":
            # Subject is a mission; object is an astronaut crew member
            return f"{obj} was a crew member of {subj}"
        if p == "alternativename":
            return f"{subj} is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"{subj} served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj} is the state bird of {subj}"
        if p == "leader":
            return f"{obj} is the leader of {subj}"
        if p == "affiliation":
            return f"{subj} is affiliated with {obj}"
        if p == "competein":
            return f"{subj} competes in {obj}"
        if p == "president":
            return f"{obj} is the president of {subj}"
        if p == "gemstone":
            return f"{obj} is a gemstone found in {subj}"
        if p == "mascot":
            return f"{obj} is the mascot of {subj}"
        if p == "cosparid":
            return f"{subj} has COSPAR ID {obj}"
        if p == "utcoffset":
            return f"{subj} has a UTC offset of {obj}"
        if p == "part":
            return f"{subj} is part of {obj}"
        if p == "ispartof":
            return f"{subj} is part of {obj}"
        if p == "higher":
            return f"{subj} is higher than {obj}"
        if p == "fossil":
            return f"{obj} is a fossil from {subj}"
        if p == "partsType".lower():
            return f"{subj}'s parts type is {obj}"
        # Generic fallback
        return f"{subj} {pred} {obj}"

    # ----------------------------------------------------------------------
    # Combine mission/crewMembers triples into a single sentence when possible
    # ----------------------------------------------------------------------
    from collections import defaultdict

    # Map mission -> set of astronaut names
    mission_to_astronauts = defaultdict(list)
    # Keep track of which triples have been consumed for the combined sentence
    consumed = set()

    for idx, t in enumerate(triples):
        pred = t.predicate.lower().replace(" ", "")
        if pred == "mission":
            mission = t.object.strip().strip('"')
            astronaut = t.subject
            mission_to_astronauts[mission].append((astronaut, idx))
            consumed.add(idx)
        elif pred == "crewmembers":
            mission = t.subject
            astronaut = t.object
            mission_to_astronauts[mission].append((astronaut, idx))
            consumed.add(idx)

    combined_sentences = []
    for mission, astro_idx_list in mission_to_astronauts.items():
        astronauts = [a for a, _ in astro_idx_list]
        # If only one astronaut, fall back to normal phrasing later
        if len(astronauts) == 1:
            # Mark this triple as not consumed so it will be handled by generic logic
            consumed.discard(astro_idx_list[0][1])
            continue
        # Build a natural list string
        if len(astronauts) == 2:
            astro_str = f"{astronauts[0]} and {astronauts[1]}"
        else:
            astro_str = ", ".join(astronauts[:-1]) + f", and {astronauts[-1]}"
        combined_sentences.append(f"{astro_str} were crew members of {mission}")

    # ----------------------------------------------------------------------
    # Group remaining triples by subject (excluding those already used)
    # ----------------------------------------------------------------------
    groups = defaultdict(list)
    for idx, t in enumerate(triples):
        if idx in consumed:
            continue
        groups[t.subject].append(t)

    sentences = []
    for subj, items in groups.items():
        parts = [phrase(subj, t.predicate, t.object) for t in items]
        if len(parts) == 1:
            sent = parts[0]
        else:
            sent = ", ".join(parts[:-1]) + ", and " + parts[-1]
        sentences.append(sent)

    # Append the combined mission sentences (if any)
    if combined_sentences:
        sentences = combined_sentences + sentences

    # Combine subject sentences
    return " ".join(sentences).strip() + "."

# EVOLVE-BLOCK-END
